def update_tsv_interpretations(tsv_path, id_col, interp_col, interp_dict):
    """Add interpretations to TSV rows that don't already have one.

    Only fills in rows where interp_col is missing/NaN/empty.
    Existing interpretations are never overwritten.
    """
    df = pd.read_csv(tsv_path, sep="\t")
    if interp_col not in df.columns:
        df[interp_col] = pd.NA

    needs_interp = df[interp_col].isna() | (df[interp_col].astype(str).str.strip() == "")
    n_new = 0
    for idx in df[needs_interp].index:
        key = df.loc[idx, id_col]
        if key in interp_dict:
            df.loc[idx, interp_col] = interp_dict[key]
            n_new += 1

    df.to_csv(tsv_path, sep="\t", index=False)
    return len(df), n_new


def update_report(idf, cdf):
    """Append new gene/combo sections to report. Never remove existing sections.

    Always regenerates summary tables at the bottom.
    """
    today = date.today().isoformat()
    existing_text = REPORT_MD.read_text() if REPORT_MD.exists() else ""

    # Parse which genes/combos already have sections
    import re
    existing_sections = set(re.findall(r"^### (\S+) \(", existing_text, re.MULTILINE))

    # Build new gene sections (only for genes not already in report)
    new_gene_sections = []
    for _, row in idf.sort_values("composite_score", ascending=False).iterrows():
        gene = row["Gene_Name"]
        if gene in existing_sections:
            continue
        cs = row["composite_score"]
        tier = row["consensus_tier"]
        mod = row["best_modality"]
        interp = INDIVIDUAL_INTERPRETATIONS.get(gene, "No interpretation available.")
        new_gene_sections.append(f"### {gene} (composite={cs:.4f}, {tier}, {mod})")
        new_gene_sections.append("")
        new_gene_sections.append(interp)
        new_gene_sections.append("")

    # Build new combo sections
    new_combo_sections = []
    if cdf is not None:
        for _, row in cdf.sort_values("Combo_Composite_Score", ascending=False).iterrows():
            cid = row["Combo_ID"]
            if cid in existing_sections:
                continue
            cs = row["Combo_Composite_Score"]
            tier = row["Combo_Consensus_Tier"]
            mod = row["Combo_Best_Modality"]
            interp = COMBO_INTERPRETATIONS.get(cid, "No interpretation available.")
            new_combo_sections.append(f"### {cid} (combo_composite={cs:.4f}, {tier}, {mod})")
            new_combo_sections.append("")
            new_combo_sections.append(interp)
            new_combo_sections.append("")

    if not existing_text:
        # First run — build full report
        lines = [
            f"# DrugnomeAI Druggability Report",
            f"Generated: {today}",
            "",
            "---",
            "",
            "## Individual Gene Assessments",
            "",
        ]
        # All genes
        for _, row in idf.sort_values("composite_score", ascending=False).iterrows():
            gene = row["Gene_Name"]
            cs = row["composite_score"]
            tier = row["consensus_tier"]
            mod = row["best_modality"]
            interp = INDIVIDUAL_INTERPRETATIONS.get(gene, "No interpretation available.")
            lines.append(f"### {gene} (composite={cs:.4f}, {tier}, {mod})")
            lines.append("")
            lines.append(interp)
            lines.append("")

        if cdf is not None:
            lines.append("---")
            lines.append("")
            lines.append("## Combination Assessments")
            lines.append("")
            for _, row in cdf.sort_values("Combo_Composite_Score", ascending=False).iterrows():
                cid = row["Combo_ID"]
                cs = row["Combo_Composite_Score"]
                tier = row["Combo_Consensus_Tier"]
                mod = row["Combo_Best_Modality"]
                interp = COMBO_INTERPRETATIONS.get(cid, "No interpretation available.")
                lines.append(f"### {cid} (combo_composite={cs:.4f}, {tier}, {mod})")
                lines.append("")
                lines.append(interp)
                lines.append("")

        report_body = "\n".join(lines)
    else:
        # Incremental — append new sections before summary tables
        report_body = existing_text

        # Strip old summary tables (everything from "## Summary Tables" onward)
        summary_marker = "## Summary Tables"
        if summary_marker in report_body:
            report_body = report_body[:report_body.index(summary_marker)].rstrip()

        # Append new gene sections
        if new_gene_sections:
            report_body += "\n\n" + "\n".join(new_gene_sections)
            print(f"  Appended {len(new_gene_sections) // 4} new gene sections to report")

        # Append new combo sections
        if new_combo_sections:
            if "## Combination Assessments" not in report_body:
                report_body += "\n\n---\n\n## Combination Assessments\n"
            report_body += "\n" + "\n".join(new_combo_sections)
            print(f"  Appended {len(new_combo_sections) // 4} new combo sections to report")

    # Always regenerate summary tables from current TSV data
    summary_lines = [
        "",
        "---",
        "",
        "## Summary Tables",
        "",
        "### Individual Genes (sorted by composite score)",
        "",
        "| Gene | Composite | Tier | Best Modality | Specificity | Top Decile |",
        "|------|-----------|------|---------------|-------------|------------|",
    ]
    for _, row in idf.sort_values("composite_score", ascending=False).iterrows():
        summary_lines.append(
            f"| {row['Gene_Name']} | {row['composite_score']:.4f} | "
            f"{row['consensus_tier']} | {row['best_modality']} | "
            f"{row['modality_specificity']:.3f} | "
            f"{int(row['n_runs_top_decile'])}/11 |"
        )

    if cdf is not None:
        summary_lines.append("")
        summary_lines.append("### Combinations (sorted by combo composite score)")
        summary_lines.append("")
        summary_lines.append("| Combo | Composite | Tier | Modality | Members |")
        summary_lines.append("|-------|-----------|------|----------|---------|")
        for _, row in cdf.sort_values("Combo_Composite_Score", ascending=False).iterrows():
            summary_lines.append(
                f"| {row['Combo_ID']} | {row['Combo_Composite_Score']:.4f} | "
                f"{row['Combo_Consensus_Tier']} | {row['Combo_Best_Modality']} | "
                f"{row['Member_Scores']} |"
            )

    summary_lines.append("")

    full_report = report_body.rstrip() + "\n" + "\n".join(summary_lines)
    REPORT_MD.write_text(full_report)
    return len(full_report.splitlines())


def main():
    # --- Update individual TSV (incremental — only fill missing interpretations) ---
    total, n_new = update_tsv_interpretations(
        INDIVIDUAL_TSV, "Gene_Name", "Interpretation", INDIVIDUAL_INTERPRETATIONS
    )
    print(f"Individual TSV: {total} genes, {n_new} new interpretations added")

    # --- Update combo TSV (incremental) ---
    cdf = None
    if COMBO_TSV.exists():
        total_c, n_new_c = update_tsv_interpretations(
            COMBO_TSV, "Combo_ID", "Combo_Interpretation", COMBO_INTERPRETATIONS
        )
        print(f"Combo TSV: {total_c} combos, {n_new_c} new interpretations added")
        cdf = pd.read_csv(COMBO_TSV, sep="\t")

    # --- Update report (incremental — append new sections, regenerate summary) ---
    idf = pd.read_csv(INDIVIDUAL_TSV, sep="\t")
    n_lines = update_report(idf, cdf)
    print(f"Report: {n_lines} lines -> {REPORT_MD}")


if __name__ == "__main__":
    main()
